components.shader:
precision mediump float;
uniform sampler2D tSource;
uniform float uTime;
varying vec2 vUv;
void main() {
  vec2 center = vec2(0.5);
  vec2 p = vUv - center;
  float r = length(p);
  // Mode 19: vortex - outward zoom that increases with distance
  float scale1 = 1.04 - 0.5*r;
  float turn1 = 0.06 + 0.03*sin(uTime*0.17);
  float cs = cos(turn1);
  float sn = sin(turn1);
  vec2 rotated = vec2(p.x*cs - p.y*sn, p.x*sn + p.y*cs);
  vec2 uv = rotated * (1.0/scale1) + center;
  uv = clamp(uv, 0.0, 1.0);
  gl_FragColor = texture2D(tSource, uv) * 0.985;
}
